mapper.select:
select event_id, request_id, room_id, user_id, amount, status, attempt_count, last_error, payload_json, created_at, updated_at, persisted_at
from auction_bid_persistence_log
where event_id = #{eventId}

mapper.update:
update auction_bid_persistence_log
set status = #{status},
    last_error = #{lastError},
    persisted_at = #{persistedAt},
    updated_at = #{updatedAt}
where event_id = #{eventId}

update auction_bid_persistence_log
set attempt_count = attempt_count + 1,
    updated_at = #{updatedAt}
where event_id = #{eventId}
